import { useRef, useState, useCallback } from 'react';
import {
  startOrEnd,
  getState,
  getEndStatus,
  getTimeout,
  nextTick,
} from '../utils/transitionHelpers';
import {
  PRE_ENTER,
  ENTERING,
  ENTERED,
  PRE_EXIT,
  EXITING,
} from '../constants/transitionsStatuses';

const initialStateMap = new Map();
const initialConfigMap = new Map();

/**
 * @typedef {Object} ConfigObject
 * @property {boolean} [initialEntered]
 */

/**
 * @param {any} key
 * @param {import('../constants/transitionsStatuses').Status} status
 * @param {Function} setStateMap
 * @param {import('react').RefObject<Map<any, any>>} latestStateMap
 * @param {NodeJS.Timeout} [timeoutId]
 * @param {({key, current}: {key: any; current: import('../utils/transitionHelpers').State}) => void} [onChange]
 */
const updateState = (key, status, setStateMap, latestStateMap, timeoutId, onChange) => {
  clearTimeout(timeoutId);
  const state = getState(status);
  const stateMap = new Map(latestStateMap.current);
  stateMap.set(key, state);
  setStateMap(stateMap);
  latestStateMap.current = stateMap;
  if (typeof onChange === 'function') {
    onChange({ key, current: state });
  }
};

/** @type {typeof import('@andes/common/build/hooks/useTransitionMap').useTransitionMap} */
const useTransitionMap = ({
  allowMultiple,
  enter = true,
  exit = true,
  preEnter,
  preExit,
  timeout,
  initialEntered,
  mountOnEnter,
  unmountOnExit,
  onStateChange: onChange,
} = {}) => {
  const [stateMap, setStateMap] = useState(initialStateMap);
  const latestStateMap = useRef(stateMap);
  const configMap = useRef(initialConfigMap);
  const [enterTimeout, exitTimeout] = getTimeout(timeout);

  const setItem = useCallback(
    /**
     * @param {any} key
     * @param {ConfigObject} [config]
     */
    (key, config) => {
      const { initialEntered: _initialEntered = initialEntered } = config || {};
      const status = _initialEntered ? ENTERED : startOrEnd(mountOnEnter);
      updateState(key, status, setStateMap, latestStateMap);
      configMap.current.set(key, {});
    },
    [initialEntered, mountOnEnter],
  );

  const deleteItem = useCallback(
    /** @param {any} key */
    (key) => {
      const newStateMap = new Map(latestStateMap.current);
      if (newStateMap.delete(key)) {
        setStateMap(newStateMap);
        latestStateMap.current = newStateMap;
        configMap.current.delete(key);
        return true;
      }
      return false;
    }, []);

  const endTransition = useCallback(
    /** @param {any} key */
    (key) => {
      const stateObj = latestStateMap.current.get(key);
      if (!stateObj) {
        if (process.env.NODE_ENV !== 'production') {
          console.error(`[UseTransition Hook] invalid key: ${key}`);
        }
        return;
      }

      const { timeoutId } = configMap.current.get(key);
      // eslint-disable-next-line no-underscore-dangle
      const status = getEndStatus(stateObj._s, unmountOnExit);
      if (status) {
        updateState(key, status, setStateMap, latestStateMap, timeoutId, onChange);
      }
    },
    [onChange, unmountOnExit],
  );

  const toggle = useCallback(
    /**
     * @param {any} key
     * @param {boolean} [toEnter]
     */
    (key, toEnter) => {
      const stateObj = latestStateMap.current.get(key);
      if (!stateObj) {
        if (process.env.NODE_ENV !== 'production') {
          console.error(`[UseTransition Hook] invalid key: ${key}`);
        }
        return;
      }

      const config = configMap.current.get(key);
      /** @param {import('../constants/transitionsStatuses').Status} status */
      const transitState = (status) => {
        updateState(key, status, setStateMap, latestStateMap, config.timeoutId, onChange);

        switch (status) {
          case ENTERING:
            if (enterTimeout && enterTimeout >= 0) {
              config.timeoutId = setTimeout(() => endTransition(key), enterTimeout);
            }
            break;

          case EXITING:
            if (exitTimeout && exitTimeout >= 0) {
              config.timeoutId = setTimeout(() => endTransition(key), exitTimeout);
            }
            break;

          case PRE_ENTER:
          case PRE_EXIT:
            config.timeoutId = nextTick(transitState, status);
            break;
          default:
            break;
        }
      };

      const enterStage = stateObj.isEnter;
      // eslint-disable-next-line no-param-reassign
      if (typeof toEnter !== 'boolean') toEnter = !enterStage;

      if (toEnter) {
        if (!enterStage) {
          // eslint-disable-next-line no-nested-ternary
          transitState(enter ? (preEnter ? PRE_ENTER : ENTERING) : ENTERED);
          if (!allowMultiple) {
            latestStateMap.current.forEach((_, _key) => _key !== key && toggle(_key, false));
          }
        }
      } else if (enterStage) {
        // eslint-disable-next-line no-nested-ternary
        transitState(exit ? (preExit ? PRE_EXIT : EXITING) : startOrEnd(unmountOnExit));
      }
    },
    [
      onChange,
      endTransition,
      allowMultiple,
      enter,
      exit,
      preEnter,
      preExit,
      enterTimeout,
      exitTimeout,
      unmountOnExit,
    ],
  );

  const toggleAll = useCallback(
    /** @param {boolean} [toEnter] */
    (toEnter) => {
      if (!allowMultiple && toEnter !== false) return;
      Array.from(latestStateMap.current.keys()).forEach(key => toggle(key, toEnter));
    },
    [allowMultiple, toggle],
  );

  return { stateMap, toggle, toggleAll, endTransition, setItem, deleteItem };
};

export { useTransitionMap };
